import React, { useState } from 'react'
import Card from './Card'

const BookingCard = ({ services }) => {
    const [query, setQuery] = useState("");

    return (
        <div>
            <input placeholder="Enter type of service " onChange={event => setQuery(event.target.value)} />

            <div className='flex flex-wrap justify-center items-center gap-7'>
                {
                    services.length !== 0 ? (servicesfilter(service => {
    if (query === '') {
      return post;
    } else if (post.title.toLowerCase().includes(query.toLowerCase())) {
      return post;
    }
  }).map((service, index) => (<Card key={index} service={service} />))) :
                        (<div className='text-white text-2xl font-nunito'>No Data Found</div>)
                }
            </div>
        </div>
    )
}

export default BookingCard
